/**
 * MedX mask forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Input masks for SKU, lot, and batch IDs.
 */
const MASK_TOKENS = Object.freeze({
  primary: { value: "forms-mask-primary", scope: "forms" },
  secondary: { value: "forms-mask-secondary", scope: "forms" },
  muted: { value: "forms-mask-muted", scope: "forms" },
  accent: { value: "forms-mask-accent", scope: "forms" },
  surface: { value: "forms-mask-surface", scope: "forms" },
});

const MASK_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const MASK_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const maskRegistry = new Map();
const MASK_listeners = new Set();
let MASK_seq = 0;

function createMaskId(prefix = "medx-forms-mask") {
  MASK_seq += 1;
  return `${prefix}-${MASK_seq}`;
}

function registerMask(config = {}) {
  const entryId = config.id ?? createMaskId();
  const preset = MASK_PRESETS[config.preset ?? "default"] ?? MASK_PRESETS.default;
  const token = MASK_TOKENS[config.token ?? preset.token] ?? MASK_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: MASK_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  maskRegistry.set(entryId, entry);
  notifyMaskListeners("register", entry);
  return entry;
}

function updateMask(id, patch = {}) {
  const entry = maskRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyMaskListeners("update", entry);
  return entry;
}

function resolveMask(id) {
  const entry = maskRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listMaskEntries(filter = {}) {
  let items = Array.from(maskRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onMaskEvent(listener) {
  MASK_listeners.add(listener);
  return () => MASK_listeners.delete(listener);
}

function notifyMaskListeners(type, entry) {
  for (const listener of MASK_listeners) {
    try {
      listener({ type, entry, registrySize: maskRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:mask] listener error", err.message);
    }
  }
}

function getMaskMetrics() {
  const items = listMaskEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(MASK_TOKENS).length,
    presets: Object.keys(MASK_PRESETS).length,
  };
}

async function runMedxMask() {
  console.log("[medx:ui:forms:mask] runtime initialized");
  console.log(`[medx:ui:forms:mask] tokens=${Object.keys(MASK_TOKENS).length} presets=${Object.keys(MASK_PRESETS).length}`);

  const events = [];
  onMaskEvent((e) => events.push(e.type));

  const domains = Object.keys(MASK_SUPPLY_CHAIN);
  const presets = Object.keys(MASK_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerMask({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/mask" },
    });
  }

  const first = listMaskEntries()[0];
  if (first) updateMask(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getMaskMetrics();
  const resolved = first ? resolveMask(first.id) : null;

  console.log(`[medx:ui:forms:mask] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:mask] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:mask] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:mask] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:mask] bootstrap complete");
}

module.exports = runMedxMask;
